Sub 'CheckRequiredFields'

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	&CheckRequiredFieldsResult = True
	If (true) AND &Name.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Name'), DVMessageType.error, &Name.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If (&Repository.RequiredEmail) AND &EMail.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Email'), DVMessageType.error, &EMail.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If (&Repository.RequiredPassword) AND &Password.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Password'), DVMessageType.error, &Password.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If (&Repository.RequiredPassword) AND &PasswordConf.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_Passwordconfirmation'), DVMessageType.error, &PasswordConf.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If (&Repository.RequiredFirstName) AND &FirstName.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_FirstName'), DVMessageType.error, &FirstName.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf
	If (&Repository.RequiredLastName) AND &LastName.IsEmpty()
		Msg(DVMessageGetBasicNotificationMsg('', Format('WWP_RequiredAttribute','WWP_GAM_LastName'), DVMessageType.error, &LastName.InternalName, DVMessageBoolean.True, ''))
		&CheckRequiredFieldsResult = False
	EndIf

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndSub

Sub 'AttributesSecurityCode'

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

	If true
		Name_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCellLogin CellPaddingLogin'
	Else
		Name_Cell.Class = !'col-xs-12 col-sm-6 DataContentCellLogin CellPaddingLogin'
	EndIf
	If &Repository.RequiredEmail
		EMail_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCellLogin CellPaddingLogin'
	Else
		EMail_Cell.Class = !'col-xs-12 col-sm-6 DataContentCellLogin CellPaddingLogin'
	EndIf
	If &Repository.RequiredPassword
		Password_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCellLogin CellPaddingLogin'
	Else
		Password_Cell.Class = !'col-xs-12 col-sm-6 DataContentCellLogin CellPaddingLogin'
	EndIf
	If &Repository.RequiredPassword
		PasswordConf_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCellLogin CellPaddingLogin'
	Else
		PasswordConf_Cell.Class = !'col-xs-12 col-sm-6 DataContentCellLogin CellPaddingLogin'
	EndIf
	If &Repository.RequiredFirstName
		FirstName_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCellLogin CellPaddingLogin'
	Else
		FirstName_Cell.Class = !'col-xs-12 col-sm-6 DataContentCellLogin CellPaddingLogin'
	EndIf
	If &Repository.RequiredLastName
		LastName_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCellLogin CellPaddingLogin'
	Else
		LastName_Cell.Class = !'col-xs-12 col-sm-6 DataContentCellLogin CellPaddingLogin'
	EndIf

	/* Generated by DVelop Work With Plus Pattern [End] - Do not change */

EndSub

